} 


class WebViewPage extends StatefulWidget{

  final WebViewController webView; 

  WebViewPage({this.webView}); 

  @override 
	State<StatefulWidget> createState() => _WebViewPageState(); 
} 

class _WebViewPageState extends State<WebViewPage>{ 

  WebViewController _controller; 
  bool isBack = false, isForward = false;

  void setWebController(WebViewController controller){ 
    this._controller = controller;
    //enable the java script interface. 
    this._controller.onWebViewCreated((controller) {
      controller?.getPlatform()?.invokeMethod('Javascript', 'window', 'alert("Java script called")'); 
      //add listener to forward and backward buttons 
      controller.evaluateJavascript(
        'document.querySelector("#backButton").addEventListener("click", () => history.go(-1))',
        resultCallback: (value) {
          setState(() { 
            isBack = value?.toString().contains('true'); 
          }); 
        }, 
      );
      controller.evaluateJavascript(
        'document.querySelector("#forwardButton").addEventListener("click", () => history.go(+1))',
        resultCallback: (value) {
          setState(() {
            isForward = value?.toString().contains('true');  
          }) ; 
        }
     )
    }) 
  }

  void toggleBackButton(){ 
    setState(() { 
      _controller.getPlatform()  
        ?.invokeMethod('Javascript', 'document', 'querySelector("#backButton").click();')
      .then((value) => print(value));
    });  
  } 

  void toggleForwardButton(){ 
     setState(() {
       this._controller 
         .getPlatform()
         ?.invokeMethod('Javascript', 
                        'document', 
                        'querySelector("#forwardButton").click();')
         .then((value)=>print(value));
     }); 
  }  

  @override
  Widget build(BuildContext context) {
    return Scaffold( 
      appBar : AppBar(
        title  : Text("Web View Page"), 
        leading: IconButton(iconSize :25.0, 
          icon : (isBack ? Icons.arrow_back : Icons.pause), 
          onPressed   : toggleBackButton), 
        actions : [
          FlatButton(
            child    : Text("Go to first page"), 
            textColor  : Colors.white, 
            backgroundColor: isForward 
                ? Theme.of(context).primaryColor 
                : Colors.black38, 
            onPressed     :(isForward || !isForward) 
              ? null 
              : toggleForwardButton 
          ) 
        ]
      ), 
      body    : Column(children   : [
        WebView(
          key          : Key('webview'), 
          initialUrl  : 'https://test-001.azurewebsites.net', 
          onWebViewCreated     :(controller)=>setWebController(controller),
        ),  
        SizedBox(height:20)
      ]) 
    ); 
  }
}